            padding: 10px;
            border-radius: 5px;
            box-shadow: 0 0 10px rgba(0,0,0,0.1);
        }
    </style>
</head>
<body>
    <div id="info">
        <h3>3D House Model</h3>
        <p>Left Click: Rotate | Right Click: Pan | Scroll: Zoom</p>
    </div>
    <div id="canvas-container"></div>

    <!-- Import Three.js from CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // Scene setup
        const scene = new THREE.Scene();
        const camera = new THREE.PerspectiveCamera(75, window.innerWidth / window.innerHeight, 0.1, 1000);
        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true;
        document.getElementById('canvas-container').appendChild(renderer.domElement);

        // Controls
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;

        // Lighting
        const ambientLight = new THREE.AmbientLight(0x404040, 0.5);
        scene.add(ambientLight);

        const directionalLight = new THREE.DirectionalLight(0xffffff, 1);
        directionalLight.position.set(50, 50, 50);
        directionalLight.castShadow = true;
        scene.add(directionalLight);

        // Ground
        const groundGeometry = new THREE.PlaneGeometry(200, 200);
        const groundMaterial = new THREE.MeshStandardMaterial({ color: 0x90EE90 });
        const ground = new THREE.Mesh(groundGeometry, groundMaterial);
        ground.rotation.x = -Math.PI / 2;
        ground.receiveShadow = true;
        scene.add(ground);

        // House materials
        const wallMaterial = new THREE.MeshStandardMaterial({ color: 0x8B4513 });
        const roofMaterial = new THREE.MeshStandardMaterial({ color: 0x8B0000 });
        const windowMaterial = new THREE.MeshStandardMaterial({ color: 0x87CEEB });
        const doorMaterial = new THREE.MeshStandardMaterial({ color: 0x654321 });

        // House group
        const houseGroup = new THREE.Group();

        // Walls
        const wallGeometry = new THREE.BoxGeometry(10, 6, 8);
        const walls = new THREE.Mesh(wallGeometry, wallMaterial);
        walls.position.y = 3;
        walls.castShadow = true;
        walls.receiveShadow = true;
        houseGroup.add(walls);

        // Roof
        const roofGeometry = new THREE.ConeGeometry(9, 4, 4);
        const roof = new THREE.Mesh(roofGeometry, roofMaterial);
        roof.position.y = 8;
        roof.rotation.y = Math.PI / 4;
        roof.castShadow = true;
        houseGroup.add(roof);

        // Windows
        const windowGeometry = new THREE.BoxGeometry(2, 2, 0.2);
        const window1 = new THREE.Mesh(windowGeometry, windowMaterial);
        window1.position.set(-2, 4, 3.9);
        window1.castShadow = true;
        houseGroup.add(window1);

        const window2 = new THREE.Mesh(windowGeometry, windowMaterial);
        window2.position.set(2, 4, 3.9);
        window2.castShadow = true;
        houseGroup.add(window2);

        // Door
        const doorGeometry = new THREE.BoxGeometry(2, 4, 0.2);
        const door = new THREE.Mesh(doorGeometry, doorMaterial);
        door.position.set(0, 2, 3.9);
        door.castShadow = true;
        houseGroup.add(door);

        // Add house to scene
        houseGroup.position.set(0, 0, 0);
        scene.add(houseGroup);

        // Camera position
        camera.position.set(15, 10, 15);
        camera.lookAt(0, 3, 0);

        // Animation loop
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }

        // Handle window resize
        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });

        animate();
    </script>
</body>
</html>
